function HabitTracker() {
  const days = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
  const [habits, setHabits] = React.useState([
    { name: 'Exercise', checks: [false,false,false,false,false,false,false] },
    { name: 'Read', checks: [false,false,false,false,false,false,false] },
    { name: 'Meditate', checks: [false,false,false,false,false,false,false] }
  ]);
  const [newHabit, setNewHabit] = React.useState('');
  const toggle = (hIdx, dIdx) => {
    const next = habits.map((h,i) => i===hIdx ? { ...h, checks: h.checks.map((c,j) => j===dIdx ? !c : c) } : h);
    setHabits(next);
  };
  const streak = (checks) => {
    let s = 0;
    for (let i = checks.length - 1; i >= 0; i--) { if (checks[i]) s++; else break; }
    return s;
  };
  const addHabit = () => {
    if (!newHabit.trim()) return;
    setHabits([...habits, { name: newHabit.trim(), checks: [false,false,false,false,false,false,false] }]);
    setNewHabit('');
  };
  const removeHabit = (hIdx) => {
    setHabits(habits.filter((_,i) => i !== hIdx));
  };
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: '0 0 12px 0', fontSize: 16, color: '#222' }}>Weekly Habits</h3>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input value={newHabit} onChange={(e) => setNewHabit(e.target.value)} placeholder="New habit..." style={{ flex: 1, padding: '6px 10px', borderRadius: 8, border: '1px solid #ddd', fontFamily: 'inherit' }} />
        <button onClick={addHabit} style={{ padding: '6px 12px', borderRadius: 8, border: 'none', background: '#4f46e5', color: '#fff', cursor: 'pointer', fontFamily: 'inherit' }}>Add</button>
      </div>
      <div style={{ overflow: 'auto', flex: 1 }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr repeat(7, 32px) 50px 28px', gap: 6, alignItems: 'center', fontSize: 12, color: '#666', marginBottom: 4 }}>
          <span>Habit</span>
          {days.map((d) => <span key={d} style={{ textAlign: 'center' }}>{d}</span>)}
          <span style={{ textAlign: 'center' }}>Streak</span>
          <span></span>
        </div>
        {habits.map((h, hi) => (
          <div key={hi} style={{ display: 'grid', gridTemplateColumns: '1fr repeat(7, 32px) 50px 28px', gap: 6, alignItems: 'center', marginBottom: 6 }}>
            <span style={{ fontSize: 13, fontWeight: 500, color: '#333', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{h.name}</span>
            {h.checks.map((c, di) => (
              <button key={di} onClick={() => toggle(hi, di)} style={{ width: 28, height: 28, borderRadius: 6, border: '1px solid #ccc', background: c ? '#4f46e5' : '#fff', color: c ? '#fff' : '#333', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 14 }}>
                {c ? '✓' : ''}
              </button>
            ))}
            <span style={{ textAlign: 'center', fontSize: 13, fontWeight: 600, color: '#4f46e5' }}>{streak(h.checks)}</span>
            <button onClick={() => removeHabit(hi)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: 16 }}>×</button>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<HabitTracker/>);
